SELECT class_id, class_name, description, created_at
FROM building_classes
WHERE is_active = 1;

SELECT COUNT(*) 
FROM building_classes 
WHERE is_active = 1;

SELECT COUNT(membership_id) AS active_member_count
FROM group_memberships
WHERE group_id = 0 AND is_active = 1;

SELECT object_name, location
FROM building_objects
WHERE is_active = 1;

SELECT COUNT(*) AS active_objects_count
FROM building_objects
WHERE is_active = 1;

SELECT distribution_name
FROM distributions
WHERE distribution_id = 1;
